typescript.quickStart:
import { AegisClient } from '@aegis-initiative/sdk';

const client = new AegisClient({ baseUrl: 'https://demo.aegis-platform.net' });

const decision = await client.propose({
  type: 'api_call',
  target: 'https://api.example.com/data',
  parameters: { method: 'GET' }
});

if (decision.decision === 'ALLOW') {
  // Proceed with the action
} else if (decision.decision === 'DENY') {
  console.log('Action denied:', decision.reason);
}

python.quickStart:
from aegis_sdk import AegisClient

client = AegisClient(base_url='https://demo.aegis-platform.net')

decision = client.propose(
    action_type='api_call',
    target='https://api.example.com/data',
    parameters={'method': 'GET'}
)

if decision.decision == 'ALLOW':
    # Proceed with the action
    pass
elif decision.decision == 'DENY':
    print(f'Action denied: {decision.reason}')
